function searchElement(list: string[], target: string): string | null {
  const found = list.find(item => item === target);
  return found ? found : null;
}

examples.toCode:
func search_element(list: &[String], target: &str) -> Option<String> {
    list.iter()
        .find(|&item| item == target)
        .cloned()
}
